#include <bits/stdc++.h>
using namespace std;
int s[501];
int main(){
    int n,m,k,l,r,x,y,v;
    cin>>n>>m>>k>>l>>r;
    for (int i=1;i<=k;i++){
        cin>>x>>y>>v;
        if (v<=l) v=100;
        else if (v>=r) v=0;
        s[x]+=v;
    }
    for (int j=1;j<=n;j++){
        cout<<s[j]<<" ";
    }
    return 0;
}
